tools = agent.requested_tools()

if all(tool.is_read_only for tool in tools):
    # Safe to parallelize
    results = await asyncio.gather(*[t.execute() for t in tools])
else:
    # Must serialize for state safety
    results = [await t.execute() for t in tools]

# Return in original request order
return sorted(results, key=lambda r: r.original_index)
